export type LogoVariant =
  | 'icon-orange'
  | 'icon-white'
  | 'horizontal-dark'
  | 'horizontal-white'
  | 'vertical-dark'
  | 'vertical-white';

export type LogoProduct = 'torneio' | 'ferinos';

export interface LogoProps {
  variant?: LogoVariant;
  product?: LogoProduct;
  height?: number;
  className?: string;
  'aria-label'?: string;
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function getLayout(variant: LogoVariant): 'horizontal' | 'vertical' | 'icon' {
  if (variant.startsWith('horizontal')) return 'horizontal';
  if (variant.startsWith('vertical')) return 'vertical';
  return 'icon';
}

