// ── Logo ────────────────────────────────────────────────────────────────────

export function Logo({
  variant = 'horizontal-dark',
  product,
  height = 40,
  className,
  'aria-label': ariaLabel = 'SuaArena',
}: LogoProps) {
  const rawId = useId();
  const uid = rawId.replace(/:/g, '');
  const layout = getLayout(variant);

  if (product) {
    const meta = PRODUCT_META[product][layout];
    const width = height * meta.aspect;
    return (
      <svg
        viewBox={meta.viewBox}
        width={width}
        height={height}
        fill="none"
        className={className}
        aria-label={ariaLabel}
        role="img"
      >
        {product === 'torneio' && layout === 'horizontal' && <TorneiosHorizontal uid={uid} />}
        {product === 'torneio' && layout === 'vertical'   && <TorneiosVertical uid={uid} />}
        {product === 'torneio' && layout === 'icon'       && <TorneiosIcon />}
        {product === 'ferinos' && layout === 'horizontal' && <FerinosHorizontal />}
        {product === 'ferinos' && layout === 'vertical'   && <FerinosVertical />}
        {product === 'ferinos' && layout === 'icon'       && <FerinosIcon />}
      </svg>
    );
  }

  const viewBox = VIEWBOXES[variant];
  const aspect = ASPECTS[variant];
  const width = height * aspect;

  return (
    <svg
      viewBox={viewBox}
      width={width}
      height={height}
      fill="none"
      className={className}
      aria-label={ariaLabel}
      role="img"
    >
      {variant === 'icon-orange'      && <IconOrange />}
      {variant === 'icon-white'       && <IconWhite />}
      {variant === 'horizontal-dark'  && <HorizontalDark />}
      {variant === 'horizontal-white' && <HorizontalWhite />}
      {variant === 'vertical-dark'    && <VerticalDark />}
      {variant === 'vertical-white'   && <VerticalWhite />}
    </svg>
  );
}
